// GetMutatorConfigByService returns mutator config entries for a service.
func GetMutatorConfigByService(serviceName string) []MethodMutationEntry {
	if entries, exists := ServiceMutatorConfig[serviceName]; exists {
		return entries
	}
	return []MethodMutationEntry{}
}

// GetAllServices returns all service names in mutator config.
func GetAllServices() []string {
	services := make([]string, 0, len(ServiceMutatorConfig))
	for service := range ServiceMutatorConfig {
		services = append(services, service)
	}
	return services
}
